328→// ---------------------------------------------------------------------------
329→// Context Builder
330→// ---------------------------------------------------------------------------
331→
332→function blockToPlainText(block: Block) {
333→  switch (block.type) {
334→    case "paragraph":
335→    case "heading":
336→    case "quote":
337→    case "code":
338→      return block.text;
339→    case "list":
340→      return block.items.join("\n");
341→    case "table":
342→      return [
343→        block.headers.join(" | "),
344→        ...block.rows.map((row) => row.join(" | ")),
345→      ].join("\n");
346→  }
347→}
348→
349→function summarizeSelection(
350→  sessionDetail: AdjustmentSessionDetail,
351→  job: ImportJob | undefined,
352→) {
353→  const { selection, targetFormat } = sessionDetail.session;
354→
355→  if (targetFormat === "markdown") {
356→    const markdown = job?.artifacts?.markdown ?? "";
357→    const lines = markdown.split("\n");
358→    const lineStart = selection.lineStart ?? 1;
359→    const lineEnd = selection.lineEnd ?? lineStart;
360→
361→    return {
362→      currentExcerpt:
363→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
364→        selection.selectedText,
365→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
366→      surrounding: {
367→        next: lines[lineEnd] ?? null,
368→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
369→      },
370→    };
371→  }
372→
373→  const message = job?.conversation?.messages.find(
374→    (entry) => entry.id === selection.messageId,
375→  );
376→  const currentBlock = message?.blocks[selection.blockIndex];
377→  const previousBlock =
378→    selection.blockIndex > 0
379→      ? message?.blocks[selection.blockIndex - 1]
380→      : undefined;
381→  const nextBlock = message?.blocks[selection.blockIndex + 1];
382→
383→  return {
384→    currentExcerpt: currentBlock
385→      ? blockToPlainText(currentBlock)
386→      : selection.selectedText,
387→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
388→    surrounding: {
389→      next: nextBlock ? blockToPlainText(nextBlock) : null,
390→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
391→    },
392→  };
393→}
394→
395→function buildSelectionContext(input: RunAgentTurnInput) {
396→  const { activeRules, job, sessionDetail } = input;
397→  const { selection, targetFormat } = sessionDetail.session;
398→  const selectionContext = summarizeSelection(sessionDetail, job);
399→  const lines: string[] = [];
400→
401→  lines.push("## Ausgewählter Block");
402→  lines.push(`Format: ${targetFormat}`);
403→  lines.push(
404→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockIndex: ${selection.blockIndex})`,
405→  );
406→  lines.push(`Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`);
407→  if (selection.lineStart != null) {
408→    lines.push(`Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`);
409→  }
410→  lines.push("");
411→  lines.push("Inhalt des ausgewählten Blocks:");
412→  lines.push("```");
413→  lines.push(selectionContext.currentExcerpt);
414→  lines.push("```");
415→
416→  if (selectionContext.surrounding.previous) {
417→    lines.push("");
418→    lines.push("Block davor:");
419→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
420→  }
421→  if (selectionContext.surrounding.next) {
422→    lines.push("");
423→    lines.push("Block danach:");
424→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
425→  }
426→
427→  const active = activeRules.filter((rule) => rule.status === "active").slice(0, 8);
428→  if (active.length > 0) {
429→    lines.push("");
430→    lines.push("## Bereits aktive Regeln");
431→    for (const rule of active) {
432→      const selectorStr = rule.selector
433→        ? JSON.stringify(rule.selector)
434→        : "(kein Selektor)";
435→      lines.push(`- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`);
436→    }
437→  }
438→
439→  return lines.join("\n");
440→}
441→
442→type InputMessage = {
443→  content: Array<{ text: string; type: "input_text" }>;
444→  role: "system" | "user" | "assistant";
445→};
446→
447→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
448→  const targetFormat = input.sessionDetail.session.targetFormat;
449→  const messages: InputMessage[] = [
450→    {
451→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
452→      role: "system",
453→    },
454→    {
455→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
456→      role: "user",
457→    },
458→  ];
459→
460→  // Add session messages as real multi-turn conversation so the model
461→  // understands the full dialog history and can reference prior turns.
462→  for (const msg of input.sessionDetail.messages) {
463→    messages.push({
464→      content: [{ text: msg.content, type: "input_text" }],
465→      role: msg.role === "user" ? "user" : "assistant",
466→    });
467→  }
468→
469→  return messages;
470→}
471→
472→// ---------------------------------------------------------------------------
473→// OpenAI helpers
474→// ---------------------------------------------------------------------------
475→
476→function isRecord(value: unknown): value is Record<string, unknown> {
477→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
478→}
479→
480→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
481→  if (!Array.isArray(payload.output)) {
482→    return [];
483→  }
484→
485→  return payload.output.flatMap((item) => {
486→    if (!isRecord(item) || item.type !== "function_call") {
487→      return [];
488→    }
489→
490→    const callId = typeof item.call_id === "string" ? item.call_id : null;
491→    const name = typeof item.name === "string" ? item.name : null;
492→    const args = typeof item.arguments === "string" ? item.arguments : null;
493→
494→    if (!callId || !name || !args) {
495→      return [];
496→    }
497→
498→    return [{ arguments: args, callId, name }];
499→  });
500→}
501→
502→function extractAssistantMessage(payload: ResponsesPayload) {
503→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
504→    return payload.output_text.trim();
505→  }
506→
507→  if (!Array.isArray(payload.output)) {
508→    return "";
509→  }
510→
511→  return payload.output
512→    .flatMap((item) => {
513→      if (
514→        !isRecord(item) ||
515→        item.type !== "message" ||
516→        item.role !== "assistant"
517→      ) {
518→        return [];
519→      }
520→
521→      const content = item.content;
522→      if (!Array.isArray(content)) {
523→        return [];
524→      }
525→
526→      return content.flatMap((entry) => {
527→        if (!isRecord(entry) || entry.type !== "output_text") {
528→          return [];
529→        }
530→
531→        return typeof entry.text === "string" && entry.text.trim()
532→          ? [entry.text.trim()]
533→          : [];
534→      });
535→    })
536→    .join("\n")
537→    .trim();
538→}
539→
540→async function requestOpenAiResponse(
541→  body: Record<string, unknown>,
542→  config: ReturnType<typeof readAdjustmentAiConfig>,
543→) {
544→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
545→    method: "POST",
546→    headers: {
547→      "Content-Type": "application/json",
548→      Authorization: `Bearer ${config.openai?.apiKey}`,
549→    },
550→    body: JSON.stringify({
551→      model: config.model,
552→      reasoning: { effort: "low" },
553→      store: true,
554→      ...body,
555→    }),
556→    signal: AbortSignal.timeout(config.timeoutMs),
557→  });
558→
559→  if (!response.ok) {
560→    const errorText = await response.text();
561→    throw new AgentUnavailableError(
562→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
563→    );
564→  }
565→
566→  return (await response.json()) as ResponsesPayload;
567→}
568→
569→// ---------------------------------------------------------------------------
570→// Tool execution with validation
571→// ---------------------------------------------------------------------------
572→
573→function validateEffect(effect: unknown): {
574→  ok: boolean;
575→  data?: Record<string, unknown>;
576→  error?: string;
577→} {
578→  const result = customStyleEffectSchema.safeParse(effect);
579→  if (result.success) {
580→    return { ok: true, data: result.data as Record<string, unknown> };
581→  }
582→
583→  const issues = result.error.issues
584→    .map((i) => `${i.path.join(".")}: ${i.message}`)
585→    .join("; ");
586→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
587→}
588→
589→async function executeToolCall(
590→  call: FunctionCallItem,
591→  callbacks: RunAgentTurnInput["callbacks"],
592→  actions: ActionRecord[],
593→): Promise<string> {
594→  const args = JSON.parse(call.arguments) as Record<string, unknown>;
595→
596→  if (call.name === "create_rule") {
597→    const effectValidation = validateEffect(args.effect);
598→    if (!effectValidation.ok) {
599→      return JSON.stringify({ ok: false, error: effectValidation.error });
600→    }
601→
602→    try {
603→      const { ruleId } = await callbacks.onCreateRule({
604→        selector: args.selector as Record<string, unknown>,
605→        effect: effectValidation.data as Record<string, unknown>,
606→        description: String(args.description ?? ""),
607→      });
608→      actions.push({ type: "created", ruleId });
609→      return JSON.stringify({ ok: true, ruleId });
610→    } catch (error) {
611→      return JSON.stringify({
612→        ok: false,
613→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
614→      });
615→    }
616→  }
617→
618→  if (call.name === "update_rule") {
619→    const effectValidation = validateEffect(args.effect);
620→    if (!effectValidation.ok) {
621→      return JSON.stringify({ ok: false, error: effectValidation.error });
622→    }
623→
624→    const ruleId = String(args.ruleId ?? "");
625→
626→    try {
627→      await callbacks.onUpdateRule({
628→        ruleId,
629→        effect: effectValidation.data as Record<string, unknown>,
630→        description:
631→          typeof args.description === "string" ? args.description : undefined,
632→      });
633→      actions.push({ type: "updated", ruleId });
634→      return JSON.stringify({ ok: true, ruleId });
635→    } catch (error) {
636→      return JSON.stringify({
637→        ok: false,
638→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
639→      });
640→    }
641→  }
642→
643→  if (call.name === "delete_rule") {
644→    const ruleId = String(args.ruleId ?? "");
645→
646→    try {
647→      await callbacks.onDeleteRule(ruleId);
648→      actions.push({ type: "deleted", ruleId });
649→      return JSON.stringify({ ok: true, ruleId });
650→    } catch (error) {
651→      return JSON.stringify({
652→        ok: false,
653→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
654→      });
655→    }
656→  }
657→
658→  return JSON.stringify({
659→    ok: false,
660→    error: `Unbekannter Tool-Call: ${call.name}`,
661→  });
662→}
663→
664→// ---------------------------------------------------------------------------
665→// Main agent turn
666→// ---------------------------------------------------------------------------
667→
668→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
669→  assistantMessage: string;
670→  actions: ActionRecord[];
671→}> {
672→  const config = readAdjustmentAiConfig();
673→
674→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
675→    throw new AgentUnavailableError(
676→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
677→    );
678→  }
679→
680→  const actions: ActionRecord[] = [];
681→  const targetFormat = input.sessionDetail.session.targetFormat;
682→
683→  const inputMessages = buildInputMessages(input);
684→
685→  let payload = await requestOpenAiResponse(
686→    {
687→      input: inputMessages,
688→      tool_choice: "auto",
689→      tools: buildTools(),
690→    },
691→    config,
692→  );
693→
694→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
695→    const functionCalls = extractFunctionCalls(payload);
696→    if (functionCalls.length === 0) {
697→      break;
698→    }
699→
700→    if (!payload.id) {
701→      throw new Error(
702→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
703→      );
704→    }
705→
706→    const toolOutputs = [];
707→
708→    for (const call of functionCalls) {
709→      const result = await executeToolCall(call, input.callbacks, actions);
710→      toolOutputs.push({
711→        type: "function_call_output",
712→        call_id: call.callId,
713→        output: result,
714→      });
715→    }
716→
717→    payload = await requestOpenAiResponse(
718→      {
719→        input: toolOutputs,
720→        previous_response_id: payload.id,
721→        tool_choice: "auto",
722→        tools: buildTools(),
723→      },
724→      config,
725→    );
726→  }
727→
728→  const rawMessage = extractAssistantMessage(payload);
729→  let assistantMessage: string;
730→
731→  if (rawMessage) {
732→    assistantMessage = rawMessage;
733→  } else if (actions.length > 0) {
734→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
735→  } else {
736→    // The AI returned no text and took no actions — retry once with an
737→    // explicit nudge so the user sees an actual question instead of a
738→    // generic placeholder.
739→    const retryPayload = await requestOpenAiResponse(
740→      {
741→        input: [
742→          ...inputMessages,
743→          {
744→            content: [
745→              {
746→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
747→                type: "input_text",
748→              },
749→            ],
750→            role: "user",
751→          },
752→        ],
753→        tool_choice: "none",
754→        tools: buildTools(),
755→      },
756→      config,
757→    );
758→
759→    assistantMessage =
760→      extractAssistantMessage(retryPayload) ||
761→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
762→  }
763→
764→  return { assistantMessage, actions };
765→}
766→

import type {
  AdjustmentSessionDetail,
  AdjustmentTargetFormat,
  Block,
  FormatRule,
  ImportJob,
} from "@chat-exporter/shared";

import { readAdjustmentAiConfig } from "./adjustment-ai-config.js";

export const MAX_TOOL_ROUNDS = 3;

export class AdjustmentChatUnavailableError extends Error {}

type ApplyAdjustmentRuleArgs = {
  instruction: string;
};

export type ApplyAdjustmentRuleResult = {
  ok: boolean;
  error?: string;
  rationale?: string;
  ruleId?: string;
  summary?: string;
};

type FunctionCallItem = {
  arguments: string;
  callId: string;
  name: string;
};

type RunAdjustmentChatTurnInput = {
  activeRules: FormatRule[];
  executeApplyAdjustmentRule: (
    args: ApplyAdjustmentRuleArgs,
  ) => Promise<ApplyAdjustmentRuleResult>;
  job?: ImportJob;
  sessionDetail: AdjustmentSessionDetail;
};

export type AdjustmentChatTurnResult = {
  appliedRuleId?: string;
  assistantMessage: string;
  didApplyRule: boolean;
  didRequestClarification: boolean;
  toolMessages: string[];
};

type ResponsesPayload = {
  id?: string;
  output?: unknown;
  output_text?: unknown;
};

function blockToPlainText(block: Block) {
  switch (block.type) {
    case "paragraph":
    case "heading":
    case "quote":
    case "code":
      return block.text;
    case "list":
      return block.items.join("\n");
    case "table":
      return [
        block.headers.join(" | "),
        ...block.rows.map((row) => row.join(" | ")),
      ].join("\n");
  }
}

function summarizeSelection(
  sessionDetail: AdjustmentSessionDetail,
  job: ImportJob | undefined,
) {
  const { selection, targetFormat } = sessionDetail.session;

  if (targetFormat === "markdown") {
    const markdown = job?.artifacts?.markdown ?? "";
    const lines = markdown.split("\n");
    const lineStart = selection.lineStart ?? 1;
    const lineEnd = selection.lineEnd ?? lineStart;

    return {
      currentExcerpt:
        lines.slice(lineStart - 1, lineEnd).join("\n") ||
        selection.selectedText,
      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
      surrounding: {
        next: lines[lineEnd] ?? null,
        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
      },
    };
  }

  const message = job?.conversation?.messages.find(
    (entry) => entry.id === selection.messageId,
  );
  const currentBlock = message?.blocks[selection.blockIndex];
  const previousBlock =
    selection.blockIndex > 0
      ? message?.blocks[selection.blockIndex - 1]
      : undefined;
  const nextBlock = message?.blocks[selection.blockIndex + 1];

  return {
    currentExcerpt: currentBlock
      ? blockToPlainText(currentBlock)
      : selection.selectedText,
    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
    surrounding: {
      next: nextBlock ? blockToPlainText(nextBlock) : null,
      previous: previousBlock ? blockToPlainText(previousBlock) : null,
    },
  };
}

function summarizeActiveRules(activeRules: FormatRule[]) {
  return activeRules
    .filter((rule) => rule.status === "active")
    .slice(0, 8)
    .map((rule) => ({
      compiledRule: rule.compiledRule,
      instruction: rule.instruction,
      kind: rule.kind,
      selector: rule.selector,
    }));
}

function buildChatContext(input: RunAdjustmentChatTurnInput) {
  const { activeRules, job, sessionDetail } = input;
  const { selection, targetFormat } = sessionDetail.session;

  return JSON.stringify(
    {
      activeRules: summarizeActiveRules(activeRules),
      selection,
      selectionContext: summarizeSelection(sessionDetail, job),
      sessionMessages: sessionDetail.messages.map((message) => ({
        content: message.content,
        role: message.role,
      })),
      targetFormat,
    },
    null,
    2,
  );
}

import type {
  AdjustmentPreview,
  AdjustmentSelection,
  AdjustmentSessionDetail,
