function validateCompiledPreview(
  payload: unknown,
  sessionDetail: AdjustmentSessionDetail,
): AdjustmentPreview {
  const preview = adjustmentPreviewSchema.parse({
    ...(payload && typeof payload === "object" && !Array.isArray(payload)
      ? payload
      : {}),
    sessionId: sessionDetail.session.id,
    targetFormat: sessionDetail.session.targetFormat,
  });

  const formatSchema =
    preview.targetFormat === "reader"
      ? readerDraftRuleSchema
      : markdownDraftRuleSchema;

  formatSchema.parse(preview.draftRule);

  return preview;
}

function getOutputText(payload: unknown) {
  if (payload && typeof payload === "object" && "output_text" in payload) {
    const outputText = (payload as { output_text?: unknown }).output_text;
    if (typeof outputText === "string" && outputText.trim()) {
      return outputText;
    }
  }

  if (!payload || typeof payload !== "object" || !("output" in payload)) {
    throw new Error("Responses API payload did not include output text.");
  }

  const output = (payload as { output?: unknown }).output;

  if (!Array.isArray(output)) {
    throw new Error("Responses API payload did not include output items.");
  }

  const text = output
    .flatMap((item) => {
      if (!item || typeof item !== "object" || !("content" in item)) {
        return [];
      }

      const content = (item as { content?: unknown }).content;
      if (!Array.isArray(content)) {
        return [];
      }

      return content.flatMap((entry) => {
        if (!entry || typeof entry !== "object") {
          return [];
        }

        const maybeText = (entry as { text?: unknown }).text;
        return typeof maybeText === "string" && maybeText.trim()
          ? [maybeText]
          : [];
      });
    })
    .join("\n")
    .trim();

  if (!text) {
    throw new Error(
      "Responses API payload did not contain structured JSON text.",
    );
  }

  return text;
}

async function requestOpenAiPreview(
  prompt: string,
  sessionDetail: AdjustmentSessionDetail,
  config: ReturnType<typeof readAdjustmentAiConfig>,
) {
  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${config.openai?.apiKey}`,
    },
    body: JSON.stringify({
      input: [
        {
          content: [
            {
              text: "Compile one transcript adjustment request into a strict preview JSON object. Only use supported selectors and effect types from the provided catalog. Do not invent new fields. The selected block is an example. When the prompt signals a reusable pattern (wantsBroadRule or hasLabelPrefix), generate a pattern-based selector (block_type or prefix_before_colon) so the rule applies to all matching blocks, not just the example.",
              type: "input_text",
            },
          ],
          role: "system",
        },
        {
          content: [
            {
              text: prompt,
              type: "input_text",
            },
          ],
          role: "user",
        },
      ],
      model: config.model,
      reasoning: {
        effort: "minimal",
      },
      text: {
        format: {
          name: `chat_exporter_${sessionDetail.session.targetFormat}_adjustment_preview`,
          schema: buildPreviewSchema(sessionDetail.session.targetFormat),
          strict: true,
          type: "json_schema",
        },
      },
    }),
    signal: AbortSignal.timeout(config.timeoutMs),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(
      `OpenAI Responses API returned ${response.status}: ${errorText.slice(0, 400)}`,
    );
  }

  const payload = (await response.json()) as unknown;
  return validateCompiledPreview(
    JSON.parse(getOutputText(payload)) as unknown,
    sessionDetail,
  );
}

async function requestCerebrasPreview(
  prompt: string,
  sessionDetail: AdjustmentSessionDetail,
  config: ReturnType<typeof readAdjustmentAiConfig>,
) {
  const response = await fetch(
    `${config.cerebras?.apiBaseUrl}/chat/completions`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${config.cerebras?.apiKey}`,
      },
      body: JSON.stringify({
        max_completion_tokens: config.cerebras?.maxCompletionTokens,
        messages: [
          {
            content:
              "Compile one transcript adjustment request into a strict preview JSON object. Only use supported selectors and effect types from the provided catalog. Do not invent new fields. The selected block is an example. When the prompt signals a reusable pattern (wantsBroadRule or hasLabelPrefix), generate a pattern-based selector (block_type or prefix_before_colon) so the rule applies to all matching blocks, not just the example.",
            role: "system",
          },
          {
            content: prompt,
            role: "user",
          },
        ],
        model: config.model,
        reasoning_effort: config.cerebras?.reasoningEffort,
        response_format: {
          json_schema: {
            name: `chat_exporter_${sessionDetail.session.targetFormat}_adjustment_preview`,
            schema: buildPreviewSchema(sessionDetail.session.targetFormat),
            strict: true,
          },
          type: "json_schema",
        },
        temperature: 0,
        top_p: 1,
      }),
      signal: AbortSignal.timeout(config.timeoutMs),
    },
  );

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(
      `Cerebras Chat Completions returned ${response.status}: ${errorText.slice(0, 400)}`,
    );
  }

  const payload = (await response.json()) as {
    choices?: Array<{
      message?: {
        content?: string | null;
      };
    }>;
  };
  const outputText = payload.choices?.[0]?.message?.content?.trim();

  if (!outputText) {
    throw new Error(
      "Cerebras response did not contain structured JSON content.",
    );
  }

  return validateCompiledPreview(
    JSON.parse(outputText) as unknown,
    sessionDetail,
  );
}

export async function compileAdjustmentPreviewWithAi(
  input: CompileAdjustmentPreviewInput,
): Promise<AdjustmentPreview | null> {
  const { job, sessionDetail } = input;
  const config = readAdjustmentAiConfig();

  if (
    !config.enabled ||
    !job ||
    (sessionDetail.session.targetFormat !== "reader" &&
      sessionDetail.session.targetFormat !== "markdown")
  ) {
    return null;
  }

  const prompt = buildCompilationPrompt(input);

  if (config.provider === "openai" && config.openai) {
    return requestOpenAiPreview(prompt, sessionDetail, config);
  }

  if (config.provider === "cerebras" && config.cerebras) {
    return requestCerebrasPreview(prompt, sessionDetail, config);
  }

  return null;
}
